// Renderer
// Draws tiles, players, assembly table state, order display, and game over screen.
// 640x480, tile size 32x32, map 20x13 tiles, top 32px = UI bar.

module renderer (
    input  logic        clk_25m,
    input  logic        rst,
    input  logic [9:0]  pixel_x,
    input  logic [9:0]  pixel_y,
    input  logic        video_on,

    // Game state
    input  logic        game_active,
    input  logic        game_over,

    // Player positions (tile coords)
    input  logic [4:0]  p1_tx, input logic [3:0]  p1_ty,
    input  logic [4:0]  p2_tx, input logic [3:0]  p2_ty,

    // Player items
    input  logic [4:0]  p1_item,
    input  logic [4:0]  p2_item,

    // Station and assembly table state
    input  logic [4:0]  chop_display_items [0:2],
    input  logic [4:0]  cook_display_items [0:2],
    input  logic [4:0]  assembly_items  [0:9],
    input  logic [1:0]  assembly_dishes [0:5],
    input  logic        assembly_plates [0:5],

    // Conveyor belt state
    input  logic        belt_active,
    input  logic [4:0]  belt_item,
    input  logic [1:0]  belt_segment,
    input  logic [4:0]  belt_progress,

    // Orders (3 slots): 1=burger, 2=soup noodle, 3=rice bowl
    input  logic [1:0]  order_dish  [0:2],
    input  logic [4:0]  order_timer [0:2],

    // Score and time
    input  logic [7:0]  score,
    input  logic [7:0]  seconds,
    input  logic        warn_5s,

    // VGA output
    output logic [3:0]  vga_r,
    output logic [3:0]  vga_g,
    output logic [3:0]  vga_b
);

    localparam logic [4:0] ITEM_NONE            = 5'd0;
    localparam logic [4:0] ITEM_BEEF_RAW        = 5'd1;
    localparam logic [4:0] ITEM_LETTUCE_RAW     = 5'd2;
    localparam logic [4:0] ITEM_BREAD           = 5'd3;
    localparam logic [4:0] ITEM_NOODLE_RAW      = 5'd4;
    localparam logic [4:0] ITEM_EGG_RAW         = 5'd5;
    localparam logic [4:0] ITEM_RICE_RAW        = 5'd6;
    localparam logic [4:0] ITEM_PORK_RAW        = 5'd7;
    localparam logic [4:0] ITEM_BEEF_COOKED     = 5'd8;
    localparam logic [4:0] ITEM_LETTUCE_CHOPPED = 5'd9;
    localparam logic [4:0] ITEM_NOODLE_COOKED   = 5'd10;
    localparam logic [4:0] ITEM_EGG_COOKED      = 5'd11;
    localparam logic [4:0] ITEM_RICE_COOKED     = 5'd12;
    localparam logic [4:0] ITEM_PORK_COOKED     = 5'd13;
    localparam logic [4:0] ITEM_DISH_BURGER     = 5'd14;
    localparam logic [4:0] ITEM_DISH_NOODLE     = 5'd15;
    localparam logic [4:0] ITEM_DISH_RICE_BOWL  = 5'd16;
    localparam logic [4:0] ITEM_BEEF_CHOPPED    = 5'd17;
    localparam logic [4:0] ITEM_PORK_CHOPPED    = 5'd18;
    localparam logic [4:0] ITEM_BURNT           = 5'd19;
    localparam logic [4:0] ITEM_BEEF_BURNT      = 5'd20;
    localparam logic [4:0] ITEM_PORK_BURNT      = 5'd21;
    localparam logic [4:0] ITEM_NOODLE_BURNT    = 5'd22;
    localparam logic [4:0] ITEM_EGG_BURNT       = 5'd23;
    localparam logic [4:0] ITEM_PLATE           = 5'd24;

    localparam logic [1:0] DISH_NONE       = 2'd0;
    localparam logic [1:0] DISH_BURGER     = 2'd1;
    localparam logic [1:0] DISH_NOODLE     = 2'd2;
    localparam logic [1:0] DISH_RICE_BOWL  = 2'd3;

    // Tile types
    localparam T_FLOOR       = 4'd0;
    localparam T_WALL        = 4'd1;
    localparam T_SRC_BEEF    = 4'd2;
    localparam T_SRC_LETTUCE = 4'd3;
    localparam T_SRC_BREAD   = 4'd4;
    localparam T_SRC_NOODLE  = 4'd5;
    localparam T_SRC_EGG     = 4'd6;
    localparam T_SRC_RICE    = 4'd7;
    localparam T_SRC_PORK    = 4'd8;
    localparam T_CHOP        = 4'd9;
    localparam T_COOK        = 4'd10;
    localparam T_ASM_IN      = 4'd11;
    localparam T_ASM_STORE   = 4'd12;
    localparam T_ASM_OUT     = 4'd13;
    localparam T_TRASH       = 4'd14;
    localparam T_ORDER       = 4'd15;
    localparam logic [4:0] T_BELT = 5'd16;
    localparam logic [4:0] T_SRC_PLATE = 5'd17;

    localparam logic [9:0] UI_BAR_H     = 10'd32;
    localparam logic [9:0] TILE_PIX     = 10'd32;
    localparam logic [9:0] MAP_PIX_W    = 10'd640;
    localparam logic [9:0] MAP_PIX_H    = 10'd416;

    logic [4:0] tilemap [0:12][0:19];

    integer r, c;
    initial begin
        for (r = 0; r < 13; r++)
            for (c = 0; c < 20; c++)
                tilemap[r][c] = T_FLOOR;

        for (c = 0; c < 20; c++) begin
            tilemap[0][c]  = T_WALL;
            tilemap[12][c] = T_WALL;
        end
        for (r = 0; r < 13; r++) begin
            tilemap[r][0]  = T_WALL;
            tilemap[r][19] = T_WALL;
        end

        // Ingredient sources: two edge tiles per ingredient, with gaps between zones.
        tilemap[1][1]  = T_SRC_BEEF;
        tilemap[2][1]  = T_SRC_BEEF;
        tilemap[4][1]  = T_SRC_LETTUCE;
        tilemap[5][1]  = T_SRC_LETTUCE;
        tilemap[7][1]  = T_SRC_BREAD;
        tilemap[8][1]  = T_SRC_BREAD;
        tilemap[11][2] = T_SRC_NOODLE;
        tilemap[11][3] = T_SRC_NOODLE;
        tilemap[11][5] = T_SRC_EGG;
        tilemap[11][6] = T_SRC_EGG;
        tilemap[11][8] = T_SRC_RICE;
        tilemap[11][9] = T_SRC_RICE;
        tilemap[11][11] = T_SRC_PORK;
        tilemap[11][12] = T_SRC_PORK;

        tilemap[1][4] = T_CHOP;
        tilemap[1][5] = T_CHOP;
        tilemap[1][6] = T_CHOP;

        tilemap[1][9] = T_COOK;
        tilemap[2][9] = T_COOK;
        tilemap[3][9] = T_COOK;

        // Assembly table area: x=13..18, y=1..3.
        tilemap[1][13] = T_ASM_IN;
        tilemap[2][13] = T_ASM_IN;
        for (c = 14; c <= 18; c++) begin
            tilemap[1][c] = T_ASM_STORE;
            tilemap[2][c] = T_ASM_STORE;
        end
        for (c = 13; c <= 18; c++)
            tilemap[3][c] = T_ASM_OUT;

        tilemap[6][8] = T_TRASH;
        tilemap[5][18] = T_SRC_PLATE;
        tilemap[6][18] = T_SRC_PLATE;
        tilemap[8][16]  = T_BELT;
        tilemap[9][16]  = T_BELT;
        tilemap[10][16] = T_BELT;
        tilemap[10][17] = T_BELT;
        tilemap[10][18] = T_BELT;

        tilemap[5][3]  = T_WALL;
        tilemap[5][4]  = T_WALL;
        tilemap[5][5]  = T_WALL;
        tilemap[8][10] = T_WALL;
        tilemap[8][11] = T_WALL;
        tilemap[8][12] = T_WALL;
    end

    function automatic logic [4:0] coord_to_tile(input logic [9:0] coord);
        return coord[9:5];
    endfunction

    function automatic logic [9:0] tile_to_pixel(input logic [4:0] tile);
        return {tile, 5'b0};
    endfunction

    function automatic logic [4:0] scale24_to32(input logic [4:0] v);
        return v;
    endfunction

    wire in_ui_bar = (pixel_y < UI_BAR_H);
    wire in_map    = (pixel_x < MAP_PIX_W) &&
                     (pixel_y >= UI_BAR_H) &&
                     (pixel_y < UI_BAR_H + MAP_PIX_H) &&
                     video_on;

    wire [9:0] map_y = pixel_y - UI_BAR_H;
    wire [4:0] tile_col = coord_to_tile(pixel_x);
    wire [4:0] tile_row_wide = coord_to_tile(map_y);
    wire [3:0] tile_row = tile_row_wide[3:0];
    wire [4:0] raw_px_in_tile = pixel_x - tile_to_pixel(tile_col);
    wire [4:0] raw_py_in_tile = map_y - tile_to_pixel(tile_row_wide);
    wire [4:0] px_in_tile = scale24_to32(raw_px_in_tile);
    wire [4:0] py_in_tile = scale24_to32(raw_py_in_tile);

    logic [11:0] tile_color;
    logic [11:0] floor_color;
    logic [4:0]  curr_tile;

    wire floor_checker = px_in_tile[3] ^ py_in_tile[3];
    wire floor_grout = (px_in_tile[2:0] == 3'd0) || (py_in_tile[2:0] == 3'd0);

    always_comb begin
        if (floor_grout)
            floor_color = 12'h798;
        else if (floor_checker)
            floor_color = 12'h9AA;
        else
            floor_color = 12'hDCD;
    end

    always_comb begin
        curr_tile = (in_map && tile_row < 13) ? tilemap[tile_row][tile_col] : T_FLOOR;
        case (curr_tile)
            T_FLOOR:       tile_color = floor_color;
            T_WALL:        tile_color = 12'h444;
            T_SRC_BEEF:    tile_color = 12'hB22;
            T_SRC_LETTUCE: tile_color = 12'h2B2;
            T_SRC_BREAD:   tile_color = 12'hC83;
            T_SRC_NOODLE:  tile_color = 12'hDD4;
            T_SRC_EGG:     tile_color = 12'hFE8;
            T_SRC_RICE:    tile_color = 12'hEEE;
            T_SRC_PORK:    tile_color = 12'hF8A;
            T_CHOP:        tile_color = 12'hC96;
            T_COOK:        tile_color = 12'h555;
            T_ASM_IN:      tile_color = 12'hCB8;
            T_ASM_STORE:   tile_color = 12'hDCA;
            T_ASM_OUT:     tile_color = 12'hEC9;
            T_TRASH:       tile_color = floor_color;
            T_ORDER:       tile_color = 12'h08F;
            T_BELT:        tile_color = 12'h444;
            T_SRC_PLATE:   tile_color = 12'hBDF;
            default:       tile_color = 12'h888;
        endcase
    end

    wire tile_border = (px_in_tile == 0) || (px_in_tile == 31) ||
                       (py_in_tile == 0) || (py_in_tile == 31);

    wire p1_tile_match = (tile_col == p1_tx) && (tile_row == p1_ty);
    wire p2_tile_match = (tile_col == p2_tx) && (tile_row == p2_ty);

    localparam logic [11:0] SPRITE_TRANSPARENT = 12'hF0F;

    wire [5:0] player_sprite_x = {px_in_tile, 1'b0} + 6'd1;
    wire [5:0] player_sprite_y = {py_in_tile, 1'b0} + 6'd1;
    wire [11:0] player_sprite_addr = {player_sprite_y, 6'b0} + player_sprite_x;

    logic [11:0] p1_sprite_color;
    logic [11:0] p2_sprite_color;

    player_sprite_rom u_player_sprites (
        .addr(player_sprite_addr),
        .sprite0_data(p1_sprite_color),
        .sprite1_data(p2_sprite_color)
    );

    wire p1_pixel = p1_tile_match && in_map && (p1_sprite_color != SPRITE_TRANSPARENT);
    wire p2_pixel = p2_tile_match && in_map && (p2_sprite_color != SPRITE_TRANSPARENT);

    wire p1_item_tile_match = (p1_ty != 4'd0) && (tile_col == p1_tx) &&
                              ((tile_row + 4'd1) == p1_ty);
    wire p2_item_tile_match = (p2_ty != 4'd0) && (tile_col == p2_tx) &&
                              ((tile_row + 4'd1) == p2_ty);

    logic [4:0] table_item;
    logic [1:0] table_dish;
    logic       table_plate;
    logic [4:0] station_item;
    logic [4:0] held_tile_item;

    always_comb begin
        table_item = ITEM_NONE;
        table_dish = DISH_NONE;
        table_plate = 1'b0;
        station_item = ITEM_NONE;
        held_tile_item = ITEM_NONE;

        if (in_map && tile_row == 4'd1 && tile_col >= 5'd14 && tile_col <= 5'd18)
            table_item = assembly_items[tile_col - 5'd14];
        else if (in_map && tile_row == 4'd2 && tile_col >= 5'd14 && tile_col <= 5'd18)
            table_item = assembly_items[5 + (tile_col - 5'd14)];

        if (in_map && tile_row == 4'd3 && tile_col >= 5'd13 && tile_col <= 5'd18) begin
            table_dish = assembly_dishes[tile_col - 5'd13];
            table_plate = assembly_plates[tile_col - 5'd13];
        end

        if (in_map && tile_row == 4'd1 && tile_col >= 5'd4 && tile_col <= 5'd6)
            station_item = chop_display_items[tile_col - 5'd4];
        else if (in_map && tile_col == 5'd9 && tile_row >= 4'd1 && tile_row <= 4'd3)
            station_item = cook_display_items[tile_row - 4'd1];

        if (in_map && p1_item_tile_match)
            held_tile_item = p1_item;
        else if (in_map && p2_item_tile_match)
            held_tile_item = p2_item;
    end

    wire in_table_glyph = (px_in_tile >= 9) && (px_in_tile <= 22) &&
                          (py_in_tile >= 9) && (py_in_tile <= 22);
    wire station_item_pixel = (station_item != ITEM_NONE) && in_table_glyph && in_map;
    wire table_item_pixel = (table_item != ITEM_NONE) && in_table_glyph && in_map;
    wire table_dish_pixel = (table_dish != DISH_NONE) && in_table_glyph && in_map;
    wire is_chop_tile = (curr_tile == T_CHOP);
    wire is_cook_tile = (curr_tile == T_COOK);
    wire is_asm_tile  = (curr_tile == T_ASM_IN) ||
                        (curr_tile == T_ASM_STORE) ||
                        (curr_tile == T_ASM_OUT);

    wire chop_board = is_chop_tile &&
                      (px_in_tile >= 5'd5)  && (px_in_tile <= 5'd26) &&
                      (py_in_tile >= 5'd6)  && (py_in_tile <= 5'd25);
    wire chop_board_edge = chop_board &&
                           ((px_in_tile <= 5'd6) || (px_in_tile >= 5'd25) ||
                            (py_in_tile <= 5'd7) || (py_in_tile >= 5'd24));
    wire chop_knife_handle = is_chop_tile &&
                             (px_in_tile >= 5'd7)  && (px_in_tile <= 5'd13) &&
                             (py_in_tile >= 5'd18) && (py_in_tile <= 5'd22);
    wire chop_knife_blade = is_chop_tile &&
                            (px_in_tile >= 5'd13) && (px_in_tile <= 5'd26) &&
                            (py_in_tile >= 5'd10) && (py_in_tile <= 5'd14);
    wire chop_knife_tip = is_chop_tile &&
                          (px_in_tile >= 5'd26) && (px_in_tile <= 5'd28) &&
                          (py_in_tile >= 5'd11) && (py_in_tile <= 5'd13);

    wire cook_panel_edge = is_cook_tile &&
                           (px_in_tile >= 5'd4)  && (px_in_tile <= 5'd27) &&
                           (py_in_tile >= 5'd4)  && (py_in_tile <= 5'd27) &&
                           ((px_in_tile <= 5'd6) || (px_in_tile >= 5'd25) ||
                            (py_in_tile <= 5'd6) || (py_in_tile >= 5'd25));
    wire cook_burner = is_cook_tile &&
                       (px_in_tile >= 5'd8)  && (px_in_tile <= 5'd23) &&
                       (py_in_tile >= 5'd8)  && (py_in_tile <= 5'd23) &&
                       ((px_in_tile <= 5'd10) || (px_in_tile >= 5'd21) ||
                        (py_in_tile <= 5'd10) || (py_in_tile >= 5'd21));
    wire cook_pot = is_cook_tile &&
                    (px_in_tile >= 5'd10) && (px_in_tile <= 5'd21) &&
                    (py_in_tile >= 5'd12) && (py_in_tile <= 5'd22);
    wire cook_pot_edge = cook_pot &&
                         ((px_in_tile <= 5'd11) || (px_in_tile >= 5'd20) ||
                          (py_in_tile <= 5'd13) || (py_in_tile >= 5'd21));
    wire cook_handle = is_cook_tile &&
                       (((px_in_tile >= 5'd6)  && (px_in_tile <= 5'd9)) ||
                        ((px_in_tile >= 5'd22) && (px_in_tile <= 5'd25))) &&
                       (py_in_tile >= 5'd15) && (py_in_tile <= 5'd18);
    wire cook_fire = is_cook_tile &&
                     (py_in_tile >= 5'd23) && (py_in_tile <= 5'd26) &&
                     (px_in_tile >= 5'd12) && (px_in_tile <= 5'd21);
    wire cook_fire_core = is_cook_tile &&
                          (py_in_tile >= 5'd24) && (py_in_tile <= 5'd26) &&
                          (px_in_tile >= 5'd15) && (px_in_tile <= 5'd18);

    wire asm_check = (curr_tile == T_ASM_OUT) &&
                     (((px_in_tile >= 5'd11) && (px_in_tile <= 5'd14) &&
                       (py_in_tile >= 5'd17) && (py_in_tile <= 5'd20)) ||
                      ((px_in_tile >= 5'd14) && (px_in_tile <= 5'd22) &&
                       (py_in_tile >= 5'd11) && (py_in_tile <= 5'd14)));

    logic [11:0] station_detail_color;
    logic        station_detail_pixel;
    always_comb begin
        station_detail_pixel = 1'b1;
        if (chop_knife_handle)
            station_detail_color = 12'h633;
        else if (chop_knife_blade || chop_knife_tip)
            station_detail_color = 12'hDDD;
        else if (chop_board_edge)
            station_detail_color = 12'h753;
        else if (chop_board)
            station_detail_color = 12'hB74;
        else if (cook_fire_core)
            station_detail_color = 12'hFC0;
        else if (cook_fire)
            station_detail_color = 12'hF30;
        else if (cook_pot_edge || cook_handle)
            station_detail_color = 12'h111;
        else if (cook_pot)
            station_detail_color = 12'h777;
        else if (cook_burner)
            station_detail_color = 12'h111;
        else if (cook_panel_edge)
            station_detail_color = 12'h333;
        else if (asm_check)
            station_detail_color = 12'h4C6;
        else begin
            station_detail_color = 12'h000;
            station_detail_pixel = 1'b0;
        end
    end

    wire trash_tile = in_map && (curr_tile == T_TRASH);
    wire [9:0] barrel_sprite_addr = {py_in_tile, 5'b0} + px_in_tile;
    logic [11:0] barrel_sprite_color;

    barrel_sprite_rom u_barrel_sprite (
        .addr(barrel_sprite_addr),
        .data(barrel_sprite_color)
    );

    wire barrel_sprite_pixel = trash_tile &&
                               (barrel_sprite_color != SPRITE_TRANSPARENT);

    wire is_belt_tile = (curr_tile == T_BELT);
    wire belt_corner_tile = is_belt_tile && (tile_col == 5'd16) && (tile_row == 4'd10);
    wire belt_down_dir = is_belt_tile && (tile_col == 5'd16) && (tile_row < 4'd10);
    wire belt_right_dir = is_belt_tile && !belt_down_dir && !belt_corner_tile;
    wire belt_straight_track = is_belt_tile &&
                               (belt_down_dir ?
                                ((px_in_tile >= 5'd7) && (px_in_tile <= 5'd24)) :
                                ((py_in_tile >= 5'd7) && (py_in_tile <= 5'd24)));
    wire belt_corner_track = belt_corner_tile &&
                             (((px_in_tile >= 5'd7) && (px_in_tile <= 5'd24) &&
                               (py_in_tile <= 5'd16)) ||
                              ((py_in_tile >= 5'd7) && (py_in_tile <= 5'd24) &&
                               (px_in_tile >= 5'd16)) ||
                              ((px_in_tile >= 5'd12) && (px_in_tile <= 5'd24) &&
                               (py_in_tile >= 5'd12) && (py_in_tile <= 5'd24)));
    wire belt_track = belt_corner_tile ? belt_corner_track : belt_straight_track;
    wire belt_straight_edge = belt_straight_track &&
                              (belt_down_dir ?
                               ((px_in_tile == 5'd7) || (px_in_tile == 5'd24)) :
                               ((py_in_tile == 5'd7) || (py_in_tile == 5'd24)));
    wire belt_corner_edge = belt_corner_track &&
                            ((px_in_tile == 5'd7 && py_in_tile <= 5'd16) ||
                             (py_in_tile == 5'd7 && px_in_tile >= 5'd16) ||
                             (px_in_tile == 5'd24) ||
                             (py_in_tile == 5'd24 && px_in_tile >= 5'd16) ||
                             (px_in_tile == 5'd16 && py_in_tile >= 5'd16) ||
                             (py_in_tile == 5'd16 && px_in_tile <= 5'd16));
    wire belt_edge = belt_corner_tile ? belt_corner_edge : belt_straight_edge;
    wire [5:0] belt_corner_sum = {1'b0, px_in_tile} + {1'b0, py_in_tile};
    wire belt_corner_arrow = belt_corner_tile &&
                             (px_in_tile >= 5'd15) && (px_in_tile <= 5'd24) &&
                             (py_in_tile >= 5'd14) && (py_in_tile <= 5'd23) &&
                             (belt_corner_sum >= 6'd35) &&
                             (belt_corner_sum <= 6'd42);
    wire belt_arrow = is_belt_tile &&
                      (belt_corner_arrow ||
                       (belt_down_dir &&
                        (py_in_tile >= 5'd15) && (py_in_tile <= 5'd23) &&
                        (px_in_tile >= (5'd16 - (py_in_tile - 5'd15))) &&
                        (px_in_tile <= (5'd16 + (py_in_tile - 5'd15)))) ||
                       (belt_right_dir &&
                        (px_in_tile >= 5'd15) && (px_in_tile <= 5'd23) &&
                        (py_in_tile >= (5'd16 - (px_in_tile - 5'd15))) &&
                        (py_in_tile <= (5'd16 + (px_in_tile - 5'd15)))));

    logic [11:0] belt_detail_color;
    logic        belt_detail_pixel;
    always_comb begin
        if (belt_arrow) begin
            belt_detail_color = 12'hDDD;
            belt_detail_pixel = 1'b1;
        end else if (belt_edge) begin
            belt_detail_color = 12'h222;
            belt_detail_pixel = 1'b1;
        end else if (belt_track) begin
            belt_detail_color = 12'h777;
            belt_detail_pixel = 1'b1;
        end else begin
            belt_detail_color = 12'h000;
            belt_detail_pixel = 1'b0;
        end
    end

    function automatic logic [11:0] dish_color(input logic [1:0] dish);
        case (dish)
            DISH_BURGER:    return 12'hF80;
            DISH_NOODLE:    return 12'hFF8;
            DISH_RICE_BOWL: return 12'hDDF;
            default:        return 12'h333;
        endcase
    endfunction

    function automatic logic [11:0] item_color(input logic [4:0] item);
        case (item)
            ITEM_BEEF_RAW:        return 12'hB22;
            ITEM_LETTUCE_RAW:     return 12'h2B2;
            ITEM_BREAD:           return 12'hC83;
            ITEM_NOODLE_RAW:      return 12'hDD4;
            ITEM_EGG_RAW:         return 12'hFE8;
            ITEM_RICE_RAW:        return 12'hEEE;
            ITEM_PORK_RAW:        return 12'hF8A;
            ITEM_BEEF_COOKED:     return 12'hE42;
            ITEM_LETTUCE_CHOPPED: return 12'h4F4;
            ITEM_NOODLE_COOKED:   return 12'hFF5;
            ITEM_EGG_COOKED:      return 12'hFC4;
            ITEM_RICE_COOKED:     return 12'hFFF;
            ITEM_PORK_COOKED:     return 12'hD58;
            ITEM_DISH_BURGER:     return dish_color(DISH_BURGER);
            ITEM_DISH_NOODLE:     return dish_color(DISH_NOODLE);
            ITEM_DISH_RICE_BOWL:  return dish_color(DISH_RICE_BOWL);
            ITEM_BEEF_CHOPPED:    return 12'hD44;
            ITEM_PORK_CHOPPED:    return 12'hF7A;
            ITEM_BURNT:           return 12'h111;
            ITEM_BEEF_BURNT:      return 12'h111;
            ITEM_PORK_BURNT:      return 12'h111;
            ITEM_NOODLE_BURNT:    return 12'h111;
            ITEM_EGG_BURNT:       return 12'h111;
            ITEM_PLATE:           return 12'hFFF;
            default:              return 12'h000;
        endcase
    endfunction

    logic [11:0] ui_color;
    always_comb begin
        ui_color = 12'h003;
        if (warn_5s && pixel_x[4])
            ui_color = 12'h300;
    end

    function automatic logic digit_pixel(
        input logic [3:0] digit,
        input logic [4:0] sx,
        input logic [4:0] sy
    );
        logic [6:0] seg;
        logic a, b, c, d, e, f, g;
        begin
            case (digit)
                4'd0: seg = 7'b1111110;
                4'd1: seg = 7'b0110000;
                4'd2: seg = 7'b1101101;
                4'd3: seg = 7'b1111001;
                4'd4: seg = 7'b0110011;
                4'd5: seg = 7'b1011011;
                4'd6: seg = 7'b1011111;
                4'd7: seg = 7'b1110000;
                4'd8: seg = 7'b1111111;
                4'd9: seg = 7'b1111011;
                default: seg = 7'b0000000;
            endcase

            a = seg[6] && (sx >= 5'd2)  && (sx <= 5'd13) && (sy <= 5'd1);
            b = seg[5] && (sx >= 5'd12) && (sx <= 5'd13) && (sy >= 5'd2)  && (sy <= 5'd8);
            c = seg[4] && (sx >= 5'd12) && (sx <= 5'd13) && (sy >= 5'd11) && (sy <= 5'd17);
            d = seg[3] && (sx >= 5'd2)  && (sx <= 5'd13) && (sy >= 5'd18) && (sy <= 5'd19);
            e = seg[2] && (sx <= 5'd1)  && (sy >= 5'd11) && (sy <= 5'd17);
            f = seg[1] && (sx <= 5'd1)  && (sy >= 5'd2)  && (sy <= 5'd8);
            g = seg[0] && (sx >= 5'd2)  && (sx <= 5'd13) && (sy >= 5'd9)  && (sy <= 5'd10);
            return a || b || c || d || e || f || g;
        end
    endfunction

    wire [3:0] score_hundreds = score / 8'd100;
    wire [3:0] score_tens     = (score / 8'd10) % 8'd10;
    wire [3:0] score_ones     = score % 8'd10;

    wire in_score_h = (pixel_x >= 10'd584) && (pixel_x < 10'd600) &&
                      (pixel_y >= 10'd6)   && (pixel_y < 10'd26);
    wire in_score_t = (pixel_x >= 10'd602) && (pixel_x < 10'd618) &&
                      (pixel_y >= 10'd6)   && (pixel_y < 10'd26);
    wire in_score_o = (pixel_x >= 10'd620) && (pixel_x < 10'd636) &&
                      (pixel_y >= 10'd6)   && (pixel_y < 10'd26);
    wire score_pixel = (in_score_h && digit_pixel(score_hundreds, pixel_x - 10'd584, pixel_y - 10'd6)) ||
                       (in_score_t && digit_pixel(score_tens,     pixel_x - 10'd602, pixel_y - 10'd6)) ||
                       (in_score_o && digit_pixel(score_ones,     pixel_x - 10'd620, pixel_y - 10'd6));

    wire order_port0_tile = 1'b0;
    wire order_port1_tile = 1'b0;
    wire order_port2_tile = 1'b0;
    wire in_order_port_inner = (px_in_tile >= 5'd4) && (px_in_tile <= 5'd27) &&
                               (py_in_tile >= 5'd4) && (py_in_tile <= 5'd27);

    logic [1:0] order_port_dish;
    logic [4:0] order_port_timer;
    always_comb begin
        order_port_dish = DISH_NONE;
        order_port_timer = 5'd0;
        if (order_port0_tile) begin
            order_port_dish = order_dish[0];
            order_port_timer = order_timer[0];
        end else if (order_port1_tile) begin
            order_port_dish = order_dish[1];
            order_port_timer = order_timer[1];
        end else if (order_port2_tile) begin
            order_port_dish = order_dish[2];
            order_port_timer = order_timer[2];
        end
    end
    wire order_port_pixel = in_order_port_inner && (order_port_dish != DISH_NONE);

    localparam logic [4:0] FOOD_SPR_NONE              = 5'd0;
    localparam logic [4:0] FOOD_SPR_COW               = 5'd1;
    localparam logic [4:0] FOOD_SPR_BROCCOLI          = 5'd2;
    localparam logic [4:0] FOOD_SPR_BREAD             = 5'd3;
    localparam logic [4:0] FOOD_SPR_BEEF              = 5'd4;
    localparam logic [4:0] FOOD_SPR_PATTY             = 5'd5;
    localparam logic [4:0] FOOD_SPR_HAMBURGER         = 5'd6;
    localparam logic [4:0] FOOD_SPR_NOODLE            = 5'd7;
    localparam logic [4:0] FOOD_SPR_EGG               = 5'd8;
    localparam logic [4:0] FOOD_SPR_COOKED_NOODLE     = 5'd9;
    localparam logic [4:0] FOOD_SPR_FRIED_EGG         = 5'd10;
    localparam logic [4:0] FOOD_SPR_NOODLE_EGG_BOWL   = 5'd11;
    localparam logic [4:0] FOOD_SPR_RICE_BOWL         = 5'd12;
    localparam logic [4:0] FOOD_SPR_PIG               = 5'd13;
    localparam logic [4:0] FOOD_SPR_PORK_BLOCK        = 5'd14;
    localparam logic [4:0] FOOD_SPR_PORK_CHOP         = 5'd15;
    localparam logic [4:0] FOOD_SPR_PORK_BOWL         = 5'd16;
    localparam logic [4:0] FOOD_SPR_SMOKE_FIRE        = 5'd17;
    localparam logic [4:0] FOOD_SPR_CABBAGE_BOWL      = 5'd18;
    localparam logic [4:0] FOOD_SPR_PLATE             = 5'd19;

    function automatic logic is_burnt_item(input logic [4:0] item);
        return (item == ITEM_BURNT)        ||
               (item == ITEM_BEEF_BURNT)   ||
               (item == ITEM_PORK_BURNT)   ||
               (item == ITEM_NOODLE_BURNT) ||
               (item == ITEM_EGG_BURNT);
    endfunction

    function automatic logic [4:0] food_sprite_for_item(input logic [4:0] item);
        case (item)
            ITEM_BEEF_RAW:        return FOOD_SPR_COW;
            ITEM_LETTUCE_RAW:     return FOOD_SPR_BROCCOLI;
            ITEM_LETTUCE_CHOPPED: return FOOD_SPR_CABBAGE_BOWL;
            ITEM_BREAD:           return FOOD_SPR_BREAD;
            ITEM_NOODLE_RAW:      return FOOD_SPR_NOODLE;
            ITEM_EGG_RAW:         return FOOD_SPR_EGG;
            ITEM_RICE_RAW:        return FOOD_SPR_RICE_BOWL;
            ITEM_RICE_COOKED:     return FOOD_SPR_RICE_BOWL;
            ITEM_PORK_RAW:        return FOOD_SPR_PIG;
            ITEM_BEEF_CHOPPED:    return FOOD_SPR_BEEF;
            ITEM_BEEF_COOKED:     return FOOD_SPR_PATTY;
            ITEM_PORK_CHOPPED:    return FOOD_SPR_PORK_BLOCK;
            ITEM_PORK_COOKED:     return FOOD_SPR_PORK_CHOP;
            ITEM_NOODLE_COOKED:   return FOOD_SPR_COOKED_NOODLE;
            ITEM_EGG_COOKED:      return FOOD_SPR_FRIED_EGG;
            ITEM_DISH_BURGER:     return FOOD_SPR_HAMBURGER;
            ITEM_DISH_NOODLE:     return FOOD_SPR_NOODLE_EGG_BOWL;
            ITEM_DISH_RICE_BOWL:  return FOOD_SPR_PORK_BOWL;
            ITEM_BEEF_BURNT:      return FOOD_SPR_PATTY;
            ITEM_PORK_BURNT:      return FOOD_SPR_PORK_CHOP;
            ITEM_NOODLE_BURNT:    return FOOD_SPR_COOKED_NOODLE;
            ITEM_EGG_BURNT:       return FOOD_SPR_FRIED_EGG;
            ITEM_BURNT:           return FOOD_SPR_SMOKE_FIRE;
            ITEM_PLATE:           return FOOD_SPR_PLATE;
            default:              return FOOD_SPR_NONE;
        endcase
    endfunction

    function automatic logic [4:0] food_sprite_for_dish(input logic [1:0] dish);
        case (dish)
            DISH_BURGER:    return FOOD_SPR_HAMBURGER;
            DISH_NOODLE:    return FOOD_SPR_NOODLE_EGG_BOWL;
            DISH_RICE_BOWL: return FOOD_SPR_PORK_BOWL;
            default:        return FOOD_SPR_NONE;
        endcase
    endfunction

    function automatic logic [4:0] food_sprite_for_source(input logic [4:0] tile);
        case (tile)
            T_SRC_BEEF:    return FOOD_SPR_COW;
            T_SRC_LETTUCE: return FOOD_SPR_BROCCOLI;
            T_SRC_BREAD:   return FOOD_SPR_BREAD;
            T_SRC_NOODLE:  return FOOD_SPR_NOODLE;
            T_SRC_EGG:     return FOOD_SPR_EGG;
            T_SRC_RICE:    return FOOD_SPR_RICE_BOWL;
            T_SRC_PORK:    return FOOD_SPR_PIG;
            T_SRC_PLATE:   return FOOD_SPR_PLATE;
            default:       return FOOD_SPR_NONE;
        endcase
    endfunction

    function automatic logic is_dish_item(input logic [4:0] item);
        return (item == ITEM_DISH_BURGER) ||
               (item == ITEM_DISH_NOODLE) ||
               (item == ITEM_DISH_RICE_BOWL);
    endfunction

    function automatic logic plate_base_pixel(
        input logic [4:0] sx,
        input logic [4:0] sy
    );
        begin
            plate_base_pixel =
                (sy >= 5'd9 && sy <= 5'd25 && sx >= 5'd3 && sx <= 5'd28) &&
                !((sy == 5'd9 || sy == 5'd25) && (sx < 5'd8 || sx > 5'd23)) &&
                !((sy == 5'd10 || sy == 5'd24) && (sx < 5'd5 || sx > 5'd26));
        end
    endfunction

    function automatic logic [11:0] plate_base_color(
        input logic [4:0] sx,
        input logic [4:0] sy
    );
        begin
            if (sy <= 5'd11 || sy >= 5'd23 || sx <= 5'd5 || sx >= 5'd26)
                plate_base_color = 12'hCCC;
            else
                plate_base_color = 12'hFFF;
        end
    endfunction

    wire held_item_fallback_pixel = (held_tile_item != ITEM_NONE) && in_table_glyph &&
                                    (food_sprite_for_item(held_tile_item) == FOOD_SPR_NONE) && in_map;

    logic [4:0] food_sprite_sel;
    logic [4:0] food_overlay_sel;
    logic       food_sprite_plated;
    always_comb begin
        food_sprite_sel = FOOD_SPR_NONE;
        food_overlay_sel = FOOD_SPR_NONE;
        food_sprite_plated = 1'b0;

        if (p1_item_tile_match && p1_item != ITEM_NONE) begin
            food_sprite_sel = food_sprite_for_item(p1_item);
            food_sprite_plated = is_dish_item(p1_item);
            if (is_burnt_item(p1_item))
                food_overlay_sel = FOOD_SPR_SMOKE_FIRE;
        end else if (p2_item_tile_match && p2_item != ITEM_NONE) begin
            food_sprite_sel = food_sprite_for_item(p2_item);
            food_sprite_plated = is_dish_item(p2_item);
            if (is_burnt_item(p2_item))
                food_overlay_sel = FOOD_SPR_SMOKE_FIRE;
        end else if (station_item != ITEM_NONE) begin
            food_sprite_sel = food_sprite_for_item(station_item);
            if (is_burnt_item(station_item))
                food_overlay_sel = FOOD_SPR_SMOKE_FIRE;
        end else if (table_item != ITEM_NONE) begin
            food_sprite_sel = food_sprite_for_item(table_item);
            if (is_burnt_item(table_item))
                food_overlay_sel = FOOD_SPR_SMOKE_FIRE;
        end else if (table_dish != DISH_NONE) begin
            food_sprite_sel = food_sprite_for_dish(table_dish);
            food_sprite_plated = 1'b1;
        end else if (table_plate) begin
            food_sprite_sel = FOOD_SPR_PLATE;
        end else if (order_port_dish != DISH_NONE) begin
            food_sprite_sel = food_sprite_for_dish(order_port_dish);
        end else begin
            food_sprite_sel = food_sprite_for_source(curr_tile);
        end
    end

    wire food_sprite_is_64x48 = (food_sprite_sel != FOOD_SPR_NONE) &&
                                (food_sprite_sel != FOOD_SPR_COW) &&
                                (food_sprite_sel != FOOD_SPR_BREAD) &&
                                (food_sprite_sel != FOOD_SPR_CABBAGE_BOWL) &&
                                (food_sprite_sel != FOOD_SPR_PLATE);
    wire food_sprite_48_y_valid = (py_in_tile >= 5'd4) && (py_in_tile <= 5'd27);
    wire food_sprite_plated_area = food_sprite_plated &&
                                   (px_in_tile >= 5'd6) && (px_in_tile <= 5'd25) &&
                                   (py_in_tile >= 5'd8) && (py_in_tile <= 5'd23);
    wire food_sprite_area = (food_sprite_sel != FOOD_SPR_NONE) &&
                            (food_sprite_plated ? food_sprite_plated_area :
                             (!food_sprite_is_64x48 || food_sprite_48_y_valid));
    wire [4:0] food_sprite_plated_x_base = px_in_tile - 5'd6;
    wire [4:0] food_sprite_plated_y_base = py_in_tile - 5'd8;
    wire [5:0] food_sprite_plated_x = ({1'b0, food_sprite_plated_x_base} << 1) +
                                      {1'b0, food_sprite_plated_x_base} + 6'd2;
    wire [5:0] food_sprite_plated_y = ({1'b0, food_sprite_plated_y_base} << 1) +
                                      {1'b0, food_sprite_plated_y_base} + 6'd1;
    wire [5:0] food_sprite_x = food_sprite_plated ?
                               food_sprite_plated_x :
                               ({px_in_tile, 1'b0} + 6'd1);
    wire [4:0] food_sprite_48_y_base = food_sprite_48_y_valid ? (py_in_tile - 5'd4) : 5'd0;
    wire [5:0] food_sprite_y = food_sprite_is_64x48 ?
                               (food_sprite_plated ?
                                food_sprite_plated_y :
                                ({food_sprite_48_y_base, 1'b0} + 6'd1)) :
                               (food_sprite_plated ?
                                food_sprite_plated_y :
                                ({py_in_tile, 1'b0} + 6'd1));
    wire [11:0] food_sprite_addr = {food_sprite_y, 6'b0} + food_sprite_x;
    logic [11:0] food_overlay_color;

    food_sprite_rom u_food_overlay (
        .sprite_sel(food_overlay_sel),
        .addr(food_sprite_addr),
        .data(food_overlay_color)
    );

    wire food_overlay_pixel = in_map && food_sprite_area &&
                              (food_overlay_color != SPRITE_TRANSPARENT);
    wire map_plated_plate_pixel = in_map && food_sprite_plated &&
                                  plate_base_pixel(px_in_tile, py_in_tile);

    logic [9:0] belt_item_x;
    logic [9:0] belt_item_y;
    wire [4:0] belt_screen_progress = belt_progress;
    always_comb begin
        case (belt_segment)
            2'd0: begin
                belt_item_x = tile_to_pixel(5'd16);
                belt_item_y = UI_BAR_H + tile_to_pixel(5'd8) + belt_screen_progress;
            end
            2'd1: begin
                belt_item_x = tile_to_pixel(5'd16);
                belt_item_y = UI_BAR_H + tile_to_pixel(5'd9) + belt_screen_progress;
            end
            2'd2: begin
                belt_item_x = tile_to_pixel(5'd16) + belt_screen_progress;
                belt_item_y = UI_BAR_H + tile_to_pixel(5'd10);
            end
            default: begin
                belt_item_x = tile_to_pixel(5'd17) + belt_screen_progress;
                belt_item_y = UI_BAR_H + tile_to_pixel(5'd10);
            end
        endcase
    end

    wire belt_item_area = belt_active &&
                          (pixel_x >= belt_item_x) && (pixel_x < belt_item_x + TILE_PIX) &&
                          (pixel_y >= belt_item_y) && (pixel_y < belt_item_y + TILE_PIX);
    wire [4:0] belt_rel_x = belt_item_area ? scale24_to32(pixel_x - belt_item_x) : 5'd0;
    wire [4:0] belt_rel_y = belt_item_area ? scale24_to32(pixel_y - belt_item_y) : 5'd0;
    wire [4:0] belt_sprite_sel = food_sprite_for_item(belt_item);
    wire belt_sprite_plated = is_dish_item(belt_item);
    wire belt_sprite_is_64x48 = (belt_sprite_sel != FOOD_SPR_NONE) &&
                                (belt_sprite_sel != FOOD_SPR_COW) &&
                                (belt_sprite_sel != FOOD_SPR_BREAD) &&
                                (belt_sprite_sel != FOOD_SPR_CABBAGE_BOWL) &&
                                (belt_sprite_sel != FOOD_SPR_PLATE);
    wire belt_sprite_48_y_valid = (belt_rel_y >= 5'd4) && (belt_rel_y <= 5'd27);
    wire belt_sprite_plated_area = belt_sprite_plated &&
                                   (belt_rel_x >= 5'd6) && (belt_rel_x <= 5'd25) &&
                                   (belt_rel_y >= 5'd8) && (belt_rel_y <= 5'd23);
    wire belt_sprite_area = belt_item_area &&
                            (belt_sprite_plated ? belt_sprite_plated_area :
                             (!belt_sprite_is_64x48 || belt_sprite_48_y_valid));
    wire [4:0] belt_sprite_plated_x_base = belt_rel_x - 5'd6;
    wire [4:0] belt_sprite_plated_y_base = belt_rel_y - 5'd8;
    wire [5:0] belt_sprite_plated_x = ({1'b0, belt_sprite_plated_x_base} << 1) +
                                      {1'b0, belt_sprite_plated_x_base} + 6'd2;
    wire [5:0] belt_sprite_plated_y = ({1'b0, belt_sprite_plated_y_base} << 1) +
                                      {1'b0, belt_sprite_plated_y_base} + 6'd1;
    wire [5:0] belt_sprite_x = belt_sprite_plated ?
                               belt_sprite_plated_x :
                               ({belt_rel_x, 1'b0} + 6'd1);
    wire [4:0] belt_sprite_48_y_base = belt_sprite_48_y_valid ? (belt_rel_y - 5'd4) : 5'd0;
    wire [5:0] belt_sprite_y = belt_sprite_is_64x48 ?
                               (belt_sprite_plated ?
                                belt_sprite_plated_y :
                                ({belt_sprite_48_y_base, 1'b0} + 6'd1)) :
                               (belt_sprite_plated ?
                                belt_sprite_plated_y :
                                ({belt_rel_y, 1'b0} + 6'd1));
    wire [11:0] belt_sprite_addr = {belt_sprite_y, 6'b0} + belt_sprite_x;
    wire belt_plated_plate_pixel = belt_item_area && belt_sprite_plated &&
                                   plate_base_pixel(belt_rel_x, belt_rel_y);
    logic [1:0] ui_order_dish;
    logic [4:0] ui_order_timer;

    always_comb begin
        ui_order_dish  = DISH_NONE;
        ui_order_timer = 5'd31;
        if (in_ui_bar && pixel_x < 10'd32) begin
            ui_order_dish  = order_dish[0];
            ui_order_timer = order_timer[0];
        end else if (in_ui_bar && pixel_x < 10'd64) begin
            ui_order_dish  = order_dish[1];
            ui_order_timer = order_timer[1];
        end else if (in_ui_bar && pixel_x < 10'd96) begin
            ui_order_dish  = order_dish[2];
            ui_order_timer = order_timer[2];
        end
    end

    wire order_ui_area = in_ui_bar &&
                         (pixel_x < 10'd96) &&
                         (ui_order_dish != DISH_NONE);
    wire [4:0] order_ui_rel_x = pixel_x[4:0];
    wire [4:0] order_ui_rel_y = pixel_y[4:0];
    wire [5:0] order_ui_sprite_x = {order_ui_rel_x, 1'b0} + 6'd1;
    wire [5:0] order_ui_sprite_y = {order_ui_rel_y, 1'b0} + 6'd1;
    wire [11:0] order_ui_sprite_addr = {order_ui_sprite_y, 6'b0} + order_ui_sprite_x;
    wire [4:0] order_ui_sprite_sel = food_sprite_for_dish(ui_order_dish);
    wire order_ui_warn_bg = order_ui_area && (ui_order_timer <= 5'd5) && pixel_x[3];

    wire use_belt_sprite = belt_sprite_area &&
                           (belt_sprite_sel != FOOD_SPR_NONE);
    wire use_order_ui_sprite = !use_belt_sprite &&
                               order_ui_area &&
                               (order_ui_sprite_sel != FOOD_SPR_NONE);
    wire use_map_food_sprite = !use_belt_sprite &&
                               !use_order_ui_sprite &&
                               in_map &&
                               food_sprite_area &&
                               (food_sprite_sel != FOOD_SPR_NONE);

    logic [4:0]  scene_food_sel;
    logic [11:0] scene_food_addr;
    logic [11:0] scene_food_color;

    always_comb begin
        if (use_belt_sprite) begin
            scene_food_sel = belt_sprite_sel;
            scene_food_addr = belt_sprite_addr;
        end else if (use_order_ui_sprite) begin
            scene_food_sel = order_ui_sprite_sel;
            scene_food_addr = order_ui_sprite_addr;
        end else if (use_map_food_sprite) begin
            scene_food_sel = food_sprite_sel;
            scene_food_addr = food_sprite_addr;
        end else begin
            scene_food_sel = FOOD_SPR_NONE;
            scene_food_addr = 12'd0;
        end
    end

    food_sprite_rom u_food_sprites (
        .sprite_sel(scene_food_sel),
        .addr(scene_food_addr),
        .data(scene_food_color)
    );

    wire scene_food_pixel = scene_food_color != SPRITE_TRANSPARENT;
    wire belt_sprite_pixel = use_belt_sprite && scene_food_pixel;
    wire order_ui_pixel = use_order_ui_sprite && scene_food_pixel;
    wire food_sprite_pixel = use_map_food_sprite && scene_food_pixel;

    wire game_over_screen = game_over && video_on;
    wire in_go_box = (pixel_x >= 160) && (pixel_x < 480) &&
                     (pixel_y >= 160) && (pixel_y < 320);

    logic [11:0] pixel_color;
    always_comb begin
        if (!video_on) begin
            pixel_color = 12'h000;
        end else if (game_over_screen) begin
            if (in_go_box)
                pixel_color = 12'h633;
            else
                pixel_color = 12'h210;
        end else if (in_ui_bar) begin
            if (order_ui_pixel) pixel_color = scene_food_color;
            else if (order_ui_warn_bg) pixel_color = 12'h500;
            else if (score_pixel) pixel_color = 12'hFF0;
            else                  pixel_color = ui_color;
        end else if (in_map) begin
            if (p1_pixel)             pixel_color = p1_sprite_color;
            else if (p2_pixel)        pixel_color = p2_sprite_color;
            else if (belt_sprite_pixel) pixel_color = scene_food_color;
            else if (belt_plated_plate_pixel) pixel_color = plate_base_color(belt_rel_x, belt_rel_y);
            else if (food_overlay_pixel) pixel_color = food_overlay_color;
            else if (food_sprite_pixel) pixel_color = scene_food_color;
            else if (map_plated_plate_pixel) pixel_color = plate_base_color(px_in_tile, py_in_tile);
            else if (held_item_fallback_pixel) pixel_color = item_color(held_tile_item);
            else if (order_port_pixel) pixel_color = (order_port_timer <= 5'd5 && pixel_x[3]) ? 12'hF00 : dish_color(order_port_dish);
            else if (station_item_pixel) pixel_color = item_color(station_item);
            else if (table_item_pixel) pixel_color = item_color(table_item);
            else if (table_dish_pixel) pixel_color = dish_color(table_dish);
            else if (barrel_sprite_pixel) pixel_color = barrel_sprite_color;
            else if (station_detail_pixel) pixel_color = station_detail_color;
            else if (belt_detail_pixel) pixel_color = belt_detail_color;
            else if (tile_border && curr_tile != T_FLOOR && curr_tile != T_TRASH) pixel_color = 12'h222;
            else                      pixel_color = tile_color;
        end else begin
            pixel_color = 12'h000;
        end
    end

    assign vga_r = pixel_color[11:8];
    assign vga_g = pixel_color[7:4];
    assign vga_b = pixel_color[3:0];

endmodule

// 32x32 RGB444 trash bin sprite, generated from barrel_128x178_rgb444.coe.
module barrel_sprite_rom (
    input  logic [9:0]  addr,
    output logic [11:0] data
);

    (* rom_style = "distributed" *) logic [11:0] barrel [0:1023];

    initial begin
`include "barrel_sprite_init.vh"
    end

    always_comb begin
        data = barrel[addr];
    end

endmodule

